import React from 'react';
import { EllipsisVerticalIcon } from '@heroicons/react/24/outline';

const UserCard = ({ user, onClick }) => {
  const getStatusColor = (availability) => {
    switch (availability) {
      case 'Available': return 'text-green-500';
      case 'In meeting': return 'text-blue-500';
      case 'Out for Lunch': return 'text-yellow-500';
      case 'Focus': return 'text-purple-500';
      case 'Emergency': return 'text-red-500';
      case 'Away': return 'text-orange-500';
      case 'Offline': return 'text-gray-500';
      default: return 'text-green-500';
    }
  };

  const getStatusDotColor = (availability) => {
    switch (availability) {
      case 'Available': return 'bg-green-500';
      case 'In meeting': return 'bg-blue-500';
      case 'Out for Lunch': return 'bg-yellow-500';
      case 'Focus': return 'bg-purple-500';
      case 'Emergency': return 'bg-red-500';
      case 'Away': return 'bg-orange-500';
      case 'Offline': return 'bg-gray-500';
      default: return 'bg-green-500';
    }
  };

  // Função para selecionar um ícone aleatório
  const getRandomIcon = () => {
    const icons = [
      '/src/components/icons/Figma-logo.svg.png',
      '/src/components/icons/Github_logo_svg.svg.png',
      '/src/components/icons/Google_Docs_logo_(2014-2020).svg.png',
      '/src/components/icons/Google_Meet_icon_(2020).svg.png',
      '/src/components/icons/Slack_icon_2019.svg.png'
    ];
    return icons[Math.floor(Math.random() * icons.length)];
  };

  return (
    <div 
      className="bg-gray-800 rounded-lg p-4 cursor-pointer hover:bg-gray-700 transition-colors"
      onClick={onClick}
    >
      {/* Header com avatar, nome, cargo e menu */}
      <div className="flex items-start gap-3 mb-3">
        <div className="relative">
          <img 
            src={user.avatar} 
            alt={`${user.name} Profile`} 
            className="w-12 h-12 rounded-full object-cover"
          />
          <div className={`absolute -bottom-1 -right-1 w-4 h-4 ${getStatusDotColor(user.availability)} rounded-full border-2 border-gray-800`}></div>
        </div>
        <div className="flex-1">
          <h3 className="text-white font-medium text-base">{user.name}</h3>
          <div className="flex items-center gap-2">
            <p className="text-gray-400 text-sm">{user.title}</p>
            <span className="text-gray-400 text-sm">• 2h</span>
          </div>
        </div>
        <EllipsisVerticalIcon className="w-5 h-5 text-gray-400" />
      </div>

      {/* Atividade atual - truncada em 1 linha */}
      <div className="mb-3">
        <p className="text-white text-sm truncate">{user.bio}</p>
      </div>

      {/* Badge de status */}
      <div className="flex items-center gap-2">
        <div className={`border border-gray-600 rounded px-2 py-1 ${getStatusColor(user.availability)}`}>
          <span className="text-xs font-medium">{user.availability}</span>
        </div>
        {/* Ícone do app */}
        <img 
          src={getRandomIcon()} 
          alt="App icon" 
          className="w-5 h-5 object-contain"
        />
      </div>
    </div>
  );
};

export default UserCard;
